#include<bits/stdc++.h>
using namespace std;
long long dp[25][100005],n,m,a[100005];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        cin>>a[i];
    }
    for(int i=0;i<=m;i++){
        for(int j=0;j<=n;j++){
            if(i==0&&j==0){
                dp[i][j]=1;
            }else if(j==0){
                dp[i][j]=dp[i-1][j]*2;
            }else if(i==0){
                dp[i][j]=dp[i][j-1]+a[j];
            }else{
                dp[i][j]=max(dp[i][j-1]+a[j],dp[i-1][j]*2);
            }
            //cout<<dp[i][j]<<' ';
        }
        //cout<<"\n";
    }
    cout<<dp[m][n];
    return 0;
}
